bash_commands.command:
awk '
/^type ReadOnlyFlagStore interface \{/,/^}/ {
  print
  if (/CountFlags\(ctx context\.Context, ns NamespaceRequest\) \(uint64, error\)/) {
    print "\tFlagExists(ctx context.Context, req ResourceRequest) (bool, error)"
  }
  next
}
1
' /workspace/internal/storage/storage.go > /tmp/storage.go && diff /workspace/internal/storage/storage.go /tmp/storage.go

awk '
/^type ReadOnlyFlagStore interface \{/,/^}/ {
  print
  if (/CountFlags\(ctx context\.Context, ns NamespaceRequest\) \(uint64, error\)/) {
    print "\tFlagExists(ctx context.Context, req ResourceRequest) (bool, error)"
  }
  next
}
1
' internal/storage/storage.go > /tmp/storage.go.fixed && cp /tmp/storage.go.fixed internal/storage/storage.go 2>&1 || true

code_changes.new_string:
// ReadOnlyFlagStore supports retrieval of flags
type ReadOnlyFlagStore interface {
	GetFlag(ctx context.Context, req ResourceRequest) (*flipt.Flag, error)
	ListFlags(ctx context.Context, req *ListRequest[NamespaceRequest]) (ResultSet[*flipt.Flag], error)
	CountFlags(ctx context.Context, ns NamespaceRequest) (uint64, error)
	FlagExists(ctx context.Context, req ResourceRequest) (bool, error)
}

